import React from 'react';
import { useNavigate } from 'react-router-dom'; // Import the navigation hook
import './Login.css';

const Login = () => {
    const navigate = useNavigate(); // Initialize the navigate function

    const handleLogin = (e) => {
        e.preventDefault();
        
        // In a real app, you'd check credentials here.
        // For now, we simulate a successful login:
        console.log("Login Successful!");
        
        // This line takes you to the Home/Dealers page
        navigate("/"); 
    };

    return (
        <div className="auth-wrapper">
            <div className="glass-card">
                <h2 className="cyber-title">Welcome Back</h2>
                <form onSubmit={handleLogin} className="cyber-form">
                    <input type="text" placeholder="Username" required />
                    <input type="password" placeholder="Password" required />
                    <button type="submit" className="cyber-button">Login</button>
                </form>
            </div>
        </div>
    );
};

export default Login;
